// COMPLETE, COMPILABLE Java code
import java.util.LinkedList;
import java.util.Queue;
import java.util.Scanner;
public class Main {
    static class Node {
        int x, y, time;
        Node(int x, int y, int time) {
            this.x = x;
            this.y = y;
            this.time = time;
        }
    }
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int M = sc.nextInt();
            int N = sc.nextInt();
            int C = sc.nextInt();
            int K = sc.nextInt();
            int[][] ghosts = new int[C][];
            for (int i = 0; i < C; i++) {
                int L = sc.nextInt();
                ghosts[i] = new int[L * 2];
                for (int j = 0; j < L; j++) {
                    ghosts[i][j * 2] = sc.nextInt();
                    ghosts[i][j * 2 + 1] = sc.nextInt();
                }
            }
            char[][] maze = new char[M][N];
            for (int i = 0; i < M; i++) {
                String s = sc.next();
                for (int j = 0; j < N; j++) {
                    maze[i][j] = s.charAt(j);
                }
            }
            int start_x = 0, start_y = 0;
            for (int i = 0; i < M; i++) {
                for (int j = 0; j < N; j++) {
                    if (maze[i][j] == '@') {
                        start_x = i;
                        start_y = j;
                    }
                }
            }
            Queue<Node> q = new LinkedList<>();
            q.offer(new Node(start_x, start_y, 0));
            boolean[][][] visited = new boolean[M][N][K + 1];
            visited[start_x][start_y][0] = true;
            while (!q.isEmpty()) {
                Node node = q.poll();
                if (node.time == K) continue;
                if (maze[node.x][node.y] == '$') {
                    System.out.println(node.time);
                    continue;
                }
                for (int dx = -1; dx <= 1; dx++) {
                    for (int dy = -1; dy <= 1; dy++) {
                        if (Math.abs(dx) + Math.abs(dy) != 1) continue;
                        int nx = node.x + dx;
                        int ny = node.y + dy;
                        if (nx < 0 || nx >= M || ny < 0 || ny >= N) continue;
                        if (maze[nx][ny] == '#') continue;
                        boolean valid = true;
                        for (int i = 0; i < C; i++) {
                            for (int j = 0; j < ghosts[i].length; j += 2) {
                                if (ghosts[i][j] == nx && ghosts[i][j + 1] == ny) {
                                    valid = false;
                                    break;
                                }
                            }
                        }
                        if (!valid) continue;
                        if (visited[nx][ny][node.time + 1]) continue;
                        q.offer(new Node(nx, ny, node.time + 1));
                        visited[nx][ny][node.time + 1] = true;
                    }
                }
            }
            System.out.println(-1);
        }
    }
}

